  const handleAnalyze = () => {
    if (!text.trim()) return;
    onAnalyze(text);
  };

  const loadSample = () => {
    setText(SAMPLE_RESUME_TEXT);
    setActiveTab('paste');
  };

  const isLoading = isProcessing || isParsing;

