import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, DomainResult, CustomEvaluationResult } from "../types";

// Ensure API key is present
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Model Constants
const FAST_MODEL = 'gemini-3-flash-preview';
const PRO_MODEL = 'gemini-3-pro-preview';

export const detectDomain = async (resumeText: string): Promise<DomainResult> => {
  if (!apiKey) throw new Error("API Key not found");

  const prompt = `
    Analyze the following resume text and detect the primary professional domain (e.g., Data Science, Software Engineering, Marketing, Finance, Sales, Design).
    Provide a confidence score (0.0 to 1.0) and a brief reasoning.

    Resume Text:
    ${resumeText.slice(0, 5000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      domain: { type: Type.STRING },
      confidence: { type: Type.NUMBER },
      reasoning: { type: Type.STRING },
    },
    required: ["domain", "confidence", "reasoning"],
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL, // Flash is sufficient for classification
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as DomainResult;
  } catch (error) {
    console.error("Domain detection failed:", error);
    throw new Error("Failed to detect domain from resume.");
  }
};

export const evaluateReadiness = async (resumeText: string, domain: string): Promise<AnalysisResult> => {
  if (!apiKey) throw new Error("API Key not found");

  const prompt = `
    You are an expert AI Readiness evaluator. 
    1. Based on the domain "${domain}", identify the top 3 critical criteria for AI readiness in this field.
    2. Evaluate the provided resume against these criteria.
    3. Calculate an overall AI Readiness Score (0-100).
    4. Assign a readiness band (e.g., "AI Ready", "Developing", "Needs Preparation").

    CRITICAL RULES:
    - Ground all scores and explanations ONLY in the provided resume text.
    - Do NOT hallucinate skills or experience.
    - If evidence is missing for a criteria, give a low score and state that evidence was not found.
    - Extract exact text snippets from the resume as evidence.

    Resume Text:
    ${resumeText.slice(0, 15000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      overallScore: { type: Type.NUMBER },
      band: { type: Type.STRING },
      criteria: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            name: { type: Type.STRING },
            score: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            evidence: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
          },
          required: ["id", "name", "score", "explanation", "evidence"],
        },
      },
    },
    required: ["overallScore", "band", "criteria"],
  };

  try {
    // Use Gemini 3 Pro for complex reasoning and evaluation
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    // Re-attach domain info since this call focuses on evaluation
    return {
      domain: { domain, confidence: 1, reasoning: "Pre-detected" },
      ...result
    } as AnalysisResult;
  } catch (error) {
    console.error("Readiness evaluation failed:", error);
    throw new Error("Failed to evaluate resume readiness.");
  }
};

export const evaluateCustomCriterion = async (resumeText: string, query: string): Promise<CustomEvaluationResult> => {
  if (!apiKey) throw new Error("API Key not found");

  const prompt = `
    User Query: "Evaluate my readiness regarding: ${query}"

    Task:
    1. Check if the resume contains ANY evidence related to "${query}".
    2. If NO evidence is found, set 'relevant' to false and explain politely.
    3. If evidence IS found, set 'relevant' to true, assign a score (0-100), explain why based on the evidence, and list the evidence snippets.

    Resume Text:
    ${resumeText.slice(0, 15000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      relevant: { type: Type.BOOLEAN },
      score: { type: Type.NUMBER, nullable: true },
      explanation: { type: Type.STRING },
      evidence: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        nullable: true
      },
    },
    required: ["relevant", "explanation"],
  };

  try {
    // Use Gemini 3 Pro for ad-hoc custom queries to ensure high quality grounding
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return {
      query,
      ...result
    } as CustomEvaluationResult;
  } catch (error) {
    console.error("Custom evaluation failed:", error);
    throw new Error("Failed to process custom evaluation request.");
  }
};

import { db } from '../db/schema';
import * as gemini from './geminiService';
import { AnalysisResult, CustomEvaluationResult } from '../types';

/**
 * API Layer
 * Mimics a backend controller architecture.
 * Handles database operations (Tables) and Service calls (AI).
 */

export const uploadResume = async (fileName: string, text: string): Promise<number> => {
  try {
    const id = await db.resumes.add({
      fileName: fileName,
      rawText: text,
      uploadedAt: new Date()
    });
    return id as number;
  } catch (error) {
    console.error("API: uploadResume failed", error);
    throw new Error("Failed to store resume.");
  }
};

export const processResumeAnalysis = async (resumeId: number): Promise<{ analysisId: number; result: AnalysisResult }> => {
  try {
    // 1. Fetch Resume from DB Table
    const resume = await db.resumes.get(resumeId);
    if (!resume) throw new Error("Resume record not found");

    // 2. Detect Domain (Service Call)
    const domainResult = await gemini.detectDomain(resume.rawText);

    // 3. Evaluate Readiness (Service Call - Gemini 3 Pro)
    const evaluation = await gemini.evaluateReadiness(resume.rawText, domainResult.domain);

    // 4. Persist Analysis Results to 'analyses' Table
    const analysisId = await db.analyses.add({
      resumeId,
      domain: domainResult.domain,
      domainConfidence: domainResult.confidence,
      domainReasoning: domainResult.reasoning,
      overallScore: evaluation.overallScore,
      band: evaluation.band,
      createdAt: new Date()
    }) as number;

    // 5. Persist Criteria to 'criteria' Table
    await db.criteria.bulkAdd(evaluation.criteria.map(c => ({
      analysisId,
      name: c.name,
      score: c.score,
      explanation: c.explanation,
      evidence: c.evidence
    })));

    return { analysisId, result: evaluation };
  } catch (error) {
    console.error("API: processResumeAnalysis failed", error);
    throw error;
  }
};

export const getAnalysisResult = async (analysisId: number): Promise<AnalysisResult> => {
  // Fetch from Tables
  const analysis = await db.analyses.get(analysisId);
  if (!analysis) throw new Error("Analysis not found");

  const criteriaRecs = await db.criteria.where('analysisId').equals(analysisId).toArray();

  // Reconstruct the Response Object
  return {
    domain: {
      domain: analysis.domain,
      confidence: analysis.domainConfidence,
      reasoning: analysis.domainReasoning
    },
    overallScore: analysis.overallScore,
    band: analysis.band,
    criteria: criteriaRecs.map(c => ({
      id: c.id?.toString() || '',
      name: c.name,
      score: c.score,
      explanation: c.explanation,
      evidence: c.evidence
    }))
  };
};

export const evaluateCustomQuery = async (resumeId: number, query: string): Promise<CustomEvaluationResult> => {
  const resume = await db.resumes.get(resumeId);
  if (!resume) throw new Error("Resume not found");

  // Call Gemini Service (Gemini 3 Pro)
  return gemini.evaluateCustomCriterion(resume.rawText, query);
};

import React, { useState, useRef } from 'react';
import { Upload, FileText, X, ClipboardType, Loader2 } from 'lucide-react';
import { SAMPLE_RESUME_TEXT } from '../constants';
import { extractTextFromPDF } from '../utils/pdfUtils';

interface ResumeInputProps {
  onAnalyze: (text: string, fileName: string) => void;
  isProcessing: boolean;
}

const ResumeInput: React.FC<ResumeInputProps> = ({ onAnalyze, isProcessing }) => {
  const [activeTab, setActiveTab] = useState<'upload' | 'paste'>('upload');
  const [text, setText] = useState('');
  const [fileName, setFileName] = useState<string | null>(null);
  const [isParsing, setIsParsing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);

    if (file.type === "application/pdf" || file.name.endsWith('.pdf')) {
      try {
        setIsParsing(true);
        // Use the PDF utility to extract text
        const extractedText = await extractTextFromPDF(file);
        setText(extractedText);
      } catch (error) {
        console.error("PDF Parsing Error", error);
        alert("Could not extract text from this PDF. It might be an image-based scan. Please try a text-based PDF or copy/paste the content.");
        setFileName(null);
        setText('');
        if (fileInputRef.current) fileInputRef.current.value = '';
      } finally {
        setIsParsing(false);
      }
    } else {
      // Handle standard text-based files
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        setText(content);
      };
      reader.onerror = () => {
        alert("Failed to read file.");
        setFileName(null);
      };
      reader.readAsText(file); 
    }
  };

  const handleClear = () => {
    setText('');
    setFileName(null);
    setIsParsing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = () => {
    if (!text.trim()) return;
    const name = fileName || "Pasted Resume Content";
    onAnalyze(text, name);
  };

  const loadSample = () => {
    setText(SAMPLE_RESUME_TEXT);
    setActiveTab('paste');
  };

  const isLoading = isProcessing || isParsing;

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        {/* Tabs */}
        <div className="flex border-b border-slate-100">
          <button
            onClick={() => setActiveTab('upload')}
            className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
              activeTab === 'upload' 
                ? 'text-indigo-600 bg-indigo-50/50 border-b-2 border-indigo-600' 
                : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
            }`}
          >
            <Upload className="w-4 h-4" />
            Upload File
          </button>
          <button
            onClick={() => setActiveTab('paste')}
            className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
              activeTab === 'paste' 
                ? 'text-indigo-600 bg-indigo-50/50 border-b-2 border-indigo-600' 
                : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
            }`}
          >
            <ClipboardType className="w-4 h-4" />
            Paste Text
          </button>
        </div>

        {/* Content */}
        <div className="p-6 md:p-8">
          {activeTab === 'upload' ? (
            <div className="space-y-6">
              <div 
                className={`border-2 border-dashed rounded-xl p-8 text-center transition-all ${
                  fileName ? 'border-emerald-300 bg-emerald-50/30' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'
                }`}
              >
                <input
                  type="file"
                  ref={fileInputRef}
                  onChange={handleFileUpload}
                  className="hidden"
                  accept=".pdf,.txt,.md,.json,.csv"
                  id="resume-upload"
                />

                {!fileName ? (
                  <label htmlFor="resume-upload" className="cursor-pointer flex flex-col items-center">
                    <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-4">
                      <FileText className="w-6 h-6" />
                    </div>
                    <p className="text-lg font-medium text-slate-700">Click to upload or drag and drop</p>
                    <p className="text-sm text-slate-500 mt-2">PDF, TXT, or Markdown supported</p>
                  </label>
                ) : (
                  <div className="flex flex-col items-center">
                    {isParsing ? (
                       <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-4 animate-spin">
                         <Loader2 className="w-6 h-6" />
                       </div>
                    ) : (
                      <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-4">
                        <FileText className="w-6 h-6" />
                      </div>
                    )}

                    <p className="text-lg font-medium text-slate-700">{fileName}</p>

                    {isParsing ? (
                      <p className="text-sm text-indigo-600 font-medium mt-2">Extracting text from PDF...</p>
                    ) : (
                      <p className="text-sm text-slate-500 mt-2">{(text.length / 1024).toFixed(1)} KB extracted</p>
                    )}

                    {!isParsing && (
                      <button 
                        onClick={handleClear}
                        className="mt-4 text-sm text-red-500 hover:text-red-600 flex items-center gap-1"
                      >
                        <X className="w-4 h-4" /> Remove
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <textarea
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Paste your resume content here..."
                className="w-full h-64 p-4 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none text-sm text-slate-700 font-mono resize-none bg-slate-50"
              />
              <div className="flex justify-between items-center text-xs text-slate-400">
                <span>{text.length} characters</span>
                <button onClick={loadSample} className="text-indigo-600 hover:underline">
                  Load Sample Resume
                </button>
              </div>
            </div>
          )}

          <div className="mt-8">
            <button
              onClick={handleAnalyze}
              disabled={!text.trim() || isLoading}
              className={`w-full py-4 rounded-xl font-semibold text-white shadow-lg shadow-indigo-200 transition-all ${
                !text.trim() || isLoading
                  ? 'bg-slate-300 cursor-not-allowed shadow-none'
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-300 hover:-translate-y-0.5'
              }`}
            >
              {isLoading ? (
                <span className="flex items-center justify-center gap-2">
                  <Loader2 className="animate-spin h-5 w-5 text-white" />
                  {isParsing ? 'Parsing PDF...' : 'Processing Resume...'}
                </span>
              ) : (
                "Analyze AI Readiness"
              )}
            </button>
          </div>
        </div>
      </div>

      <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4 text-center">
        <div className="p-4 bg-white rounded-lg border border-slate-100 shadow-sm">
          <div className="font-semibold text-indigo-600 mb-1">Grounded Evaluation</div>
          <div className="text-xs text-slate-500">Scores based ONLY on your resume evidence. No hallucinations.</div>
        </div>
        <div className="p-4 bg-white rounded-lg border border-slate-100 shadow-sm">
          <div className="font-semibold text-indigo-600 mb-1">Domain Adaptive</div>
          <div className="text-xs text-slate-500">Automatically detects your field and applies relevant criteria.</div>
        </div>
        <div className="p-4 bg-white rounded-lg border border-slate-100 shadow-sm">
          <div className="font-semibold text-indigo-600 mb-1">Persistent History</div>
          <div className="text-xs text-slate-500">Your analysis is securely stored locally in your browser's database.</div>
        </div>
      </div>
    </div>
  );
};

export default ResumeInput;

import React, { useState } from 'react';
import { Send, AlertCircle, CheckCircle } from 'lucide-react';
import * as api from '../services/api';
import { CustomEvaluationResult } from '../types';

interface CustomEvaluationProps {
  resumeId: number;
}

const CustomEvaluation: React.FC<CustomEvaluationProps> = ({ resumeId }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CustomEvaluationResult | null>(null);

  const handleEvaluate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setResult(null);
    try {
      const data = await api.evaluateCustomQuery(resumeId, query);
      setResult(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
      <h3 className="text-lg font-bold text-slate-800 mb-4">Custom Criterion Evaluation</h3>
      <p className="text-sm text-slate-500 mb-6">
        Want to know if you demonstrate specific skills like "Leadership", "Cloud Architecture", or "Strategic Planning"? 
        Ask below and we'll search your resume for evidence using our advanced Gemini 3 Pro model.
      </p>

      <form onSubmit={handleEvaluate} className="relative">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="e.g., Evaluate my evidence for Team Leadership..."
          className="w-full py-3 px-4 pr-12 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none text-slate-700 bg-slate-50"
        />
        <button
          type="submit"
          disabled={loading || !query.trim()}
          className="absolute right-2 top-2 p-1.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          {loading ? (
             <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
               <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
               <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
             </svg>
          ) : (
            <Send className="w-5 h-5" />
          )}
        </button>
      </form>

      {result && (
        <div className={`mt-6 p-5 rounded-xl border ${result.relevant ? 'bg-indigo-50 border-indigo-100' : 'bg-slate-50 border-slate-200'}`}>
          <div className="flex items-start gap-3">
            {result.relevant ? (
              <CheckCircle className="w-6 h-6 text-indigo-600 shrink-0 mt-0.5" />
            ) : (
              <AlertCircle className="w-6 h-6 text-slate-400 shrink-0 mt-0.5" />
            )}
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h4 className="font-semibold text-slate-800">
                  Result for "{result.query}"
                </h4>
                {result.relevant && result.score !== undefined && result.score !== null && (
                   <span className="px-2 py-0.5 bg-white text-indigo-700 text-xs font-bold rounded shadow-sm border border-indigo-100">
                     Score: {result.score}/100
                   </span>
                )}
              </div>
              <p className="text-slate-600 text-sm leading-relaxed mb-4">{result.explanation}</p>

              {result.evidence && result.evidence.length > 0 && (
                <div className="space-y-2">
                  <p className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Evidence Found:</p>
                  {result.evidence.map((ev, idx) => (
                    <div key={idx} className="bg-white p-3 rounded border border-slate-200 text-xs text-slate-600 italic border-l-4 border-l-indigo-300">
                      "{ev}"
