import React, { useState } from 'react';
import Layout from './components/ui/Layout';
import ResumeInput from './components/ResumeInput';
import ResultsDashboard from './components/ResultsDashboard';
import { AppState, ProcessingStage, AnalysisResult } from './types';
import * as api from './services/api';
import { AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.UPLOAD);
  const [processingStage, setProcessingStage] = useState<ProcessingStage>(ProcessingStage.IDLE);

  // State now tracks IDs for backend tables
  const [currentResumeId, setCurrentResumeId] = useState<number | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleAnalysis = async (text: string, fileName: string) => {
    setAppState(AppState.PROCESSING);
    setError(null);
    setAnalysisResult(null);
    setCurrentResumeId(null);

    try {
      // Step 1: Upload to Backend (DB Table)
      setProcessingStage(ProcessingStage.EXTRACTING);
      const resumeId = await api.uploadResume(fileName, text);
      setCurrentResumeId(resumeId);

      // Step 2: Detect Domain
      setProcessingStage(ProcessingStage.DETECTING_DOMAIN);

      // Step 3: Evaluate Readiness (Trigger Backend Processing)
      setProcessingStage(ProcessingStage.EVALUATING);
      const { result } = await api.processResumeAnalysis(resumeId);

      console.log("Evaluation complete:", result);

      setAnalysisResult(result);
      setProcessingStage(ProcessingStage.FINALIZING);

      // Small delay for UX transition
      setTimeout(() => {
        setAppState(AppState.RESULTS);
      }, 800);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unknown error occurred during analysis.");
      setAppState(AppState.ERROR);
    } finally {
      setProcessingStage(ProcessingStage.IDLE);
    }
  };

  const handleReset = () => {
    setAppState(AppState.UPLOAD);
    setCurrentResumeId(null);
    setAnalysisResult(null);
    setError(null);
  };

  return (
    <Layout>
      {appState === AppState.ERROR && (
        <div className="max-w-2xl mx-auto mb-6 bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <div className="flex-1">
             <h3 className="font-semibold">Analysis Failed</h3>
             <p className="text-sm">{error}</p>
          </div>
          <button onClick={handleReset} className="text-sm underline hover:text-red-900">Try Again</button>
        </div>
      )}

      {appState === AppState.UPLOAD || appState === AppState.PROCESSING || appState === AppState.ERROR ? (
        <div className="flex flex-col items-center justify-center py-12">
          <div className="text-center max-w-2xl mx-auto mb-12">
            <h2 className="text-4xl font-bold text-slate-900 mb-4 tracking-tight">Are you ready for the <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-violet-600">AI Workforce?</span></h2>
            <p className="text-lg text-slate-500">
              Get an instant, evidence-based AI Readiness Score grounded entirely in your resume. 
              Powered by <strong>Gemini 3 Pro</strong> and domain-adaptive analysis.
            </p>
          </div>

          <div className="w-full">
            <ResumeInput 
              onAnalyze={handleAnalysis} 
              isProcessing={appState === AppState.PROCESSING} 
            />
            {appState === AppState.PROCESSING && (
              <p className="text-center text-indigo-600 font-medium mt-6 animate-pulse">
                {processingStage}
              </p>
            )}
          </div>
        </div>
      ) : (
        analysisResult && currentResumeId && (
          <ResultsDashboard 
            result={analysisResult} 
            resumeId={currentResumeId}
            onReset={handleReset} 
          />
        )
      )}
    </Layout>
  );
};

export default App;

import Dexie, { type Table } from 'dexie';

export interface ResumeRecord {
  id?: number;
  fileName: string;
  rawText: string;
  uploadedAt: Date;
}

export interface AnalysisRecord {
  id?: number;
  resumeId: number;
  domain: string;
  domainConfidence: number;
  domainReasoning: string;
  overallScore: number;
  band: string;
  createdAt: Date;
}

export interface CriterionRecord {
  id?: number;
  analysisId: number;
  name: string;
  score: number;
  explanation: string;
  evidence: string[];
}

export class AppDatabase extends Dexie {
  resumes!: Table<ResumeRecord>;
  analyses!: Table<AnalysisRecord>;
  criteria!: Table<CriterionRecord>;

  constructor() {
    super('AIReadinessDB');
    (this as any).version(1).stores({
      resumes: '++id, uploadedAt',
      analyses: '++id, resumeId',
      criteria: '++id, analysisId'
    });
  }
}

export const db = new AppDatabase();

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, DomainResult, CustomEvaluationResult } from "../types";

// Initialize Gemini Client
// The API key is obtained from the environment variable process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Model Constants
const FAST_MODEL = 'gemini-3-flash-preview';
const PRO_MODEL = 'gemini-3-pro-preview';

export const detectDomain = async (resumeText: string): Promise<DomainResult> => {
  const prompt = `
    Analyze the following resume text and detect the primary professional domain (e.g., Data Science, Software Engineering, Marketing, Finance, Sales, Design).
    Provide a confidence score (0.0 to 1.0) and a brief reasoning.

    Resume Text:
    ${resumeText.slice(0, 5000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      domain: { type: Type.STRING },
      confidence: { type: Type.NUMBER },
      reasoning: { type: Type.STRING },
    },
    required: ["domain", "confidence", "reasoning"],
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL, // Flash is sufficient for classification
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as DomainResult;
  } catch (error) {
    console.error("Domain detection failed:", error);
    throw new Error("Failed to detect domain from resume.");
  }
};

export const evaluateReadiness = async (resumeText: string, domain: string): Promise<AnalysisResult> => {
  const prompt = `
    You are an expert AI Readiness evaluator. 
    1. Based on the domain "${domain}", identify the top 3 critical criteria for AI readiness in this field.
    2. Evaluate the provided resume against these criteria.
    3. Calculate an overall AI Readiness Score (0-100).
    4. Assign a readiness band (e.g., "AI Ready", "Developing", "Needs Preparation").

    CRITICAL RULES:
    - Ground all scores and explanations ONLY in the provided resume text.
    - Do NOT hallucinate skills or experience.
    - If evidence is missing for a criteria, give a low score and state that evidence was not found.
    - Extract exact text snippets from the resume as evidence.

    Resume Text:
    ${resumeText.slice(0, 15000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      overallScore: { type: Type.NUMBER },
      band: { type: Type.STRING },
      criteria: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            name: { type: Type.STRING },
            score: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            evidence: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
          },
          required: ["id", "name", "score", "explanation", "evidence"],
        },
      },
    },
    required: ["overallScore", "band", "criteria"],
  };

  try {
    // Use Gemini 3 Pro for complex reasoning and evaluation
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    // Re-attach domain info since this call focuses on evaluation
    return {
      domain: { domain, confidence: 1, reasoning: "Pre-detected" },
      ...result
    } as AnalysisResult;
  } catch (error) {
    console.error("Readiness evaluation failed:", error);
    throw new Error("Failed to evaluate resume readiness.");
  }
};

export const evaluateCustomCriterion = async (resumeText: string, query: string): Promise<CustomEvaluationResult> => {
  const prompt = `
    User Query: "Evaluate my readiness regarding: ${query}"

    Task:
    1. Check if the resume contains ANY evidence related to "${query}".
    2. If NO evidence is found, set 'relevant' to false and explain politely.
    3. If evidence IS found, set 'relevant' to true, assign a score (0-100), explain why based on the evidence, and list the evidence snippets.

    Resume Text:
    ${resumeText.slice(0, 15000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      relevant: { type: Type.BOOLEAN },
      score: { type: Type.NUMBER, nullable: true },
      explanation: { type: Type.STRING },
      evidence: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        nullable: true
      },
    },
    required: ["relevant", "explanation"],
  };

  try {
    // Use Gemini 3 Pro for ad-hoc custom queries to ensure high quality grounding
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return {
      query,
      ...result
    } as CustomEvaluationResult;
  } catch (error) {
    console.error("Custom evaluation failed:", error);
    throw new Error("Failed to process custom evaluation request.");
  }
};

