  const strokeDashoffset = circumference - (result.overallScore / 100) * circumference;

  const handleDomainUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (manualDomain.trim()) {
      onUpdateDomain(manualDomain);
      setManualDomain('');
    }
