          <p className="text-slate-400 text-xs mt-2">Grounded in Resume Evidence</p>
        </div>

        {/* Right: Context & Summary - 7 cols */}
        <div className="lg:col-span-7 flex flex-col gap-6">
          {/* Domain Card */}
          <div className="flex-1 bg-white rounded-3xl shadow-[0_2px_20px_-5px_rgba(0,0,0,0.1)] border border-slate-100 p-8 flex flex-col relative overflow-hidden">
