                                 </li>
                               ))}
                             </ul>
                           ) : (
                             <div className="text-sm text-slate-400 italic flex items-center gap-2">
                               <AlertTriangle className="w-4 h-4" /> No direct evidence found in resume.
                             </div>
                           )}
                         </div>
                      </div>
                   </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <CustomEvaluation resumeId={resumeId} />
    </div>
  );
};

