import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, DomainResult, CustomEvaluationResult } from "../types";

// Initialize Gemini Client
// The API key is obtained from the environment variable process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Model Constants
const FAST_MODEL = 'gemini-3-flash-preview';
const PRO_MODEL = 'gemini-3-pro-preview';

export const detectDomain = async (resumeText: string): Promise<DomainResult> => {
  const prompt = `
    Analyze the following resume text and detect the primary professional domain (e.g., Data Science, Software Engineering, Marketing, Finance, Sales, Design).
    Provide a confidence score (0.0 to 1.0) and a brief reasoning.

    Resume Text:
    ${resumeText.slice(0, 5000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      domain: { type: Type.STRING },
      confidence: { type: Type.NUMBER },
      reasoning: { type: Type.STRING },
    },
    required: ["domain", "confidence", "reasoning"],
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL, // Flash is sufficient for classification
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as DomainResult;
  } catch (error) {
    console.error("Domain detection failed:", error);
    throw new Error("Failed to detect domain from resume.");
  }
};

export const evaluateReadiness = async (resumeText: string, domain: string): Promise<AnalysisResult> => {
  const prompt = `
    ROLE: You are a STRICT and OBJECTIVE AI Career Readiness Evaluator.
    TARGET DOMAIN: "${domain}"

    OBJECTIVE:
    Assess if the candidate is ready for an AI-integrated role specifically within the TARGET DOMAIN.

    INSTRUCTIONS:
    1. Define the 3 Standard Pillars of AI Readiness for "${domain}".
       - These must be the industry-standard requirements for this specific field, NOT tailored to what the candidate knows.
       - The criteria must be CONSISTENT for this domain across different candidates.
       - Example: If domain is "Product Management", criteria might be "AI Product Lifecycle", "Data-Driven Strategy", "Cross-functional AI Leadership".
       - Example: If domain is "Data Science", criteria might be "Model Architecture", "MLOps/Deployment", "Data Engineering".

    2. Assess the Resume STRICTLY against these 3 Pillars.
       - Ignore skills irrelevant to this domain. A candidate might be an expert C++ coder, but if the domain is "Marketing", that is less relevant than "Generative AI for Content".
       - If the resume lacks evidence for a specific Pillar, assign a LOW SCORE (0-30) and explicitly state "No evidence found in resume".
       - Do NOT give benefit of the doubt. High scores in one domain (e.g. Data Science) do NOT translate to high scores in another (e.g. Sales) unless specific evidence exists.

    3. Output:
       - Overall Score (0-100)
       - Readiness Band
       - List of 3 Criteria with scores, explanations, and verbatim evidence.

    CRITICAL RULES:
    - Ground all scores ONLY in the provided resume text.
    - Quote exact text snippets from the resume as evidence.
    - If evidence is missing, score low.

    Resume Text:
    ${resumeText.slice(0, 15000)}
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      overallScore: { type: Type.NUMBER },
      band: { type: Type.STRING },
      criteria: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            name: { type: Type.STRING },
            score: { type: Type.NUMBER },
            explanation: { type: Type.STRING },
            evidence: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
          },
          required: ["id", "name", "score", "explanation", "evidence"],
        },
      },
    },
    required: ["overallScore", "band", "criteria"],
  };

  try {
    // Use Gemini 3 Pro for complex reasoning and evaluation
    const response = await ai.models.generateContent({
      model: PRO_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    // Re-attach domain info since this call focuses on evaluation
    return {
      domain: { domain, confidence: 1, reasoning: "Pre-detected" },
      ...result
    } as AnalysisResult;
  } catch (error) {
    console.error("Readiness evaluation failed:", error);
    throw new Error("Failed to evaluate resume readiness.");
  }
};

